output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?country(COUNT(?company) AS ?count) WHERE {
  {
    SELECT ?company ?revenue WHERE {
      ?company wdt:P31 wd:Q37333 .
      ?company wdt:P2139 ?revenue .
    }
    ORDER BY DESC(?revenue)
    LIMIT 50
  }
  ?company wdt:P159 ?location .
  ?location wdt:P17 ?country .
}
GROUP BY ?country
ORDER BY DESC(?count)

